    f32 centerToEnd;
    f32 minDistanceSq;
    f32 limitDistanceSq;
    f32 guardDistance;
    f32 startGuardDistance;
    f32 slope;
    f32 intercept;
    f32 perpSlope;
    f32 dx;
    f32 dz;
    f32 length;
    f32 adjustedDistance;
